  1→import React, { useEffect, useState } from 'react';
  2→import {
  3→  AlertTriangle,
  4→  ArrowLeft,
  5→  Award,
  6→  BadgeCheck,
  7→  Calendar,
  8→  Gift,
  9→  MapPin,
 10→  Settings as SettingsIcon,
 11→  Trash2,
 12→  Wallet
 13→} from 'lucide-react';
 14→import { apiJson } from '../../lib/client/api';
 15→import { getSession } from '../../lib/client/auth';
 16→import { clearSyncErrorRecords, listSyncErrorRecords, type SyncErrorRecord } from '../../lib/client/offlineQueue';
 17→import type { CollectionAssignment, MapScope, PointEvent, UserProfile } from '../../shared/types';
 18→import { categoryLabel as getCategoryLabelFromRegistry } from '../../shared/verticals';
 19→
 20→interface Props {
 21→  onBack: () => void;
 22→  onSettings: () => void;
 23→  onRedeem: () => void;
 24→  language: 'en' | 'fr';
 25→}
 26→
 27→const Profile: React.FC<Props> = ({ onBack, onSettings, onRedeem, language }) => {
 28→  const t = (en: string, fr: string) => (language === 'fr' ? fr : en);
 29→  const [profile, setProfile] = useState<UserProfile | null>(null);
 30→  const [isLoading, setIsLoading] = useState(true);
 31→  const [loadError, setLoadError] = useState('');
 32→  const [userLocation, setUserLocation] = useState(t('Location not set', 'Position non definie'));
 33→  const [history, setHistory] = useState<Array<{ id: string; date: string; location: string; type: string; xp: number }>>([]);
 34→  const [syncErrors, setSyncErrors] = useState<SyncErrorRecord[]>([]);
 35→  const [isLoadingSyncErrors, setIsLoadingSyncErrors] = useState(true);
 36→  const [isClearingSyncErrors, setIsClearingSyncErrors] = useState(false);
 37→  const [syncErrorActionError, setSyncErrorActionError] = useState('');
 38→  const [assignments, setAssignments] = useState<CollectionAssignment[]>([]);
 39→  const [isLoadingAssignments, setIsLoadingAssignments] = useState(true);
 40→  const [assignmentError, setAssignmentError] = useState('');
 41→  const [isUpdatingAssignmentId, setIsUpdatingAssignmentId] = useState<string | null>(null);
 42→  const normalizeMapScope = (value: unknown, isAdminMode: boolean): MapScope => {
 43→    if (isAdminMode) return 'global';
 44→    if (value === 'cameroon' || value === 'global') return value;
 45→    return 'bonamoussadi';
 46→  };
 47→  const activeMapScope = normalizeMapScope(profile?.mapScope, Boolean(profile?.isAdmin));
 48→  const isMapUnlocked = activeMapScope !== 'bonamoussadi';
 49→
 50→  const formatHistoryDate = (iso: string) => {
 51→    const date = new Date(iso);
 52→    if (Number.isNaN(date.getTime())) return t('Unknown', 'Inconnu');
 53→
 54→    const now = new Date();
 55→    const sameDay = now.toDateString() === date.toDateString();
 56→    const yesterday = new Date(now);
 57→    yesterday.setDate(now.getDate() - 1);
 58→    const isYesterday = yesterday.toDateString() === date.toDateString();
 59→    const time = date.toLocaleTimeString([], { hour: '2-digit', minute: '2-digit' });
 60→
 61→    if (sameDay) return language === 'fr' ? `Aujourd'hui • ${time}` : `Today • ${time}`;
 62→    if (isYesterday) return language === 'fr' ? `Hier • ${time}` : `Yesterday • ${time}`;
 63→    return `${date.toLocaleDateString([], { month: 'short', day: '2-digit' })} • ${time}`;
 64→  };
 65→
 66→  const submissionToHistory = (submission: PointEvent) => {
 67→    const details = (submission.details ?? {}) as Record<string, unknown>;
 68→    const siteName = typeof details.siteName === 'string' ? details.siteName : typeof details.name === 'string' ? details.name : null;
 69→    const locationLabel = siteName || `GPS: ${submission.location.latitude.toFixed(4)}°, ${submission.location.longitude.toFixed(4)}°`;
 70→    const typeLabel = getCategoryLabelFromRegistry(submission.category, language);
 71→    const rawXp = details.xpAwarded;
 72→    const xpAwarded = typeof rawXp === 'number' && Number.isFinite(rawXp) ? rawXp : 5;
 73→
 74→    return {
 75→      id: submission.id,
 76→      date: formatHistoryDate(submission.createdAt),
 77→      location: locationLabel,
 78→      type: typeLabel,
 79→      xp: xpAwarded
 80→    };
 81→  };
 82→
 83→  const categoryLabel = (category: SyncErrorRecord['payloadSummary']['category']) => {
 84→    return getCategoryLabelFromRegistry(category, language);
 85→  };
 86→
 87→  useEffect(() => {
 88→    const loadProfile = async () => {
 89→      try {
 90→        setIsLoading(true);
 91→        setLoadError('');
 92→        const data = await apiJson<UserProfile>('/api/user');
 93→        setProfile(data);
 94→
 95→        try {
 96→          const [session, submissions] = await Promise.all([
 97→            getSession(),
 98→            apiJson<PointEvent[]>('/api/submissions?view=events')
 99→          ]);
100→          const userId = session?.user?.id?.toLowerCase().trim();
101→          if (!userId) {
102→            setHistory([]);
103→            setUserLocation(t('Location not set', 'Position non definie'));
104→            return;
105→          }
106→
107→          const ownSubmissions = submissions
108→            .filter((submission) => (typeof submission.userId === 'string' ? submission.userId.toLowerCase().trim() : '') === userId)
109→            .sort((a, b) => new Date(b.createdAt).getTime() - new Date(a.createdAt).getTime());
110→
111→          setHistory(ownSubmissions.map(submissionToHistory));
112→
113→          const latest = ownSubmissions[0];
114→          if (latest) {
115→            const details = (latest.details ?? {}) as Record<string, unknown>;
116→            const siteName = typeof details.siteName === 'string' ? details.siteName : typeof details.name === 'string' ? details.name : null;
117→            setUserLocation(siteName || `GPS ${latest.location.latitude.toFixed(4)}°, ${latest.location.longitude.toFixed(4)}°`);
118→          } else {
119→            setUserLocation(t('No contributions yet', 'Pas encore de contributions'));
120→          }
121→        } catch {
122→          setHistory([]);
123→          setUserLocation(t('Location not set', 'Position non definie'));
124→        }
125→      } catch {
126→        setProfile(null);
127→        setLoadError(t('Unable to load profile.', 'Impossible de charger le profil.'));
128→        setHistory([]);
129→        setUserLocation(t('Location not set', 'Position non definie'));
130→      } finally {
131→        setIsLoading(false);
132→      }
133→    };
134→    loadProfile();
135→  }, [language]);
136→
137→  useEffect(() => {
138→    let cancelled = false;
139→
140→    const loadAssignments = async () => {
141→      try {
142→        setIsLoadingAssignments(true);
143→        setAssignmentError('');
144→        const data = await apiJson<CollectionAssignment[]>('/api/user?view=assignments');
145→        if (cancelled) return;
146→        setAssignments(Array.isArray(data) ? data : []);
147→      } catch (error) {
148→        if (cancelled) return;
149→        const message =
150→          error instanceof Error
151→            ? error.message
152→            : t('Unable to load assignments.', 'Impossible de charger les affectations.');
153→        setAssignmentError(message);
154→        setAssignments([]);
155→      } finally {
156→        if (!cancelled) setIsLoadingAssignments(false);
157→      }
158→    };
159→
160→    void loadAssignments();
161→    return () => {
162→      cancelled = true;
163→    };
164→  }, [language]);
165→
166→  useEffect(() => {
167→    let cancelled = false;
168→
169→    const loadSyncErrors = async () => {
170→      try {
171→        setIsLoadingSyncErrors(true);
172→        const records = await listSyncErrorRecords();
173→        if (!cancelled) setSyncErrors(records);
174→      } catch {
175→        if (!cancelled) setSyncErrors([]);
176→      } finally {
177→        if (!cancelled) setIsLoadingSyncErrors(false);
178→      }
179→    };
180→
181→    void loadSyncErrors();
182→    return () => {
183→      cancelled = true;
184→    };
185→  }, []);
186→
187→  const handleClearSyncErrors = async () => {
188→    if (isClearingSyncErrors) return;
189→    setSyncErrorActionError('');
190→    try {
191→      setIsClearingSyncErrors(true);
192→      await clearSyncErrorRecords();
193→      setSyncErrors([]);
194→    } catch {
195→      setSyncErrorActionError(t('Unable to clear sync errors.', 'Impossible d\'effacer les erreurs de synchronisation.'));
196→    } finally {
197→      setIsClearingSyncErrors(false);
198→    }
199→  };
200→
201→  const handleAssignmentStatus = async (assignmentId: string, status: CollectionAssignment['status']) => {
202→    if (isUpdatingAssignmentId) return;
203→    setAssignmentError('');
204→    try {
205→      setIsUpdatingAssignmentId(assignmentId);
206→      const updated = await apiJson<CollectionAssignment>('/api/user?view=assignments', {
207→        method: 'PATCH',
208→        headers: { 'Content-Type': 'application/json' },
209→        body: JSON.stringify({ id: assignmentId, status }),
210→      });
211→      setAssignments((prev) => prev.map((assignment) => (assignment.id === assignmentId ? updated : assignment)));
212→    } catch (error) {
213→      const message =
214→        error instanceof Error
215→          ? error.message
216→          : t('Unable to update assignment.', 'Impossible de mettre a jour l\'affectation.');
217→      setAssignmentError(message);
218→    } finally {
219→      setIsUpdatingAssignmentId(null);
220→    }
221→  };
222→
223→  return (
224→    <div className="flex flex-col h-full bg-[#f9fafb] overflow-y-auto no-scrollbar">
225→      <div className="sticky top-0 z-30 bg-white border-b border-gray-100 px-4 h-14 flex items-center justify-between">
226→        <button onClick={onBack} className="p-2 -ml-2 text-gray-700 hover:text-[#0f2b46] transition-colors">
227→          <ArrowLeft size={20} />
228→        </button>
229→        <h3 className="text-sm font-bold mx-auto">{t('Dashboard', 'Tableau de bord')}</h3>
230→        <button onClick={onSettings} className="p-2 text-[#0f2b46] absolute right-2">
231→          <SettingsIcon size={20} />
232→        </button>
233→      </div>
234→
235→      <div className="p-4 space-y-6">
236→        <div className="flex flex-col items-center py-4 text-center">
237→          <div className="relative mb-4">
238→            <div className="w-24 h-24 rounded-full border-4 border-white shadow-xl bg-[#e7eef4] overflow-hidden">
239→              <img src="https://picsum.photos/seed/jeanpaul/300/300" alt={t('avatar', 'avatar')} className="w-full h-full object-cover" />
240→            </div>
241→            <div className="absolute -bottom-1 -right-1 p-1 bg-[#4c7c59] rounded-full border-2 border-white">
242→              <BadgeCheck size={14} className="text-white" />
243→            </div>
244→          </div>
245→          <h2 className="text-xl font-bold text-gray-900">
246→            {isLoading ? (
247→              <span className="inline-block h-4 w-40 rounded-full bg-gray-200 animate-pulse"></span>
248→            ) : (
249→              profile?.name || profile?.phone || profile?.email || t('Contributor', 'Contributeur')
250→            )}
251→          </h2>
252→          {!isLoading && (
253→            <div className="flex items-center justify-center text-[10px] text-gray-400 mt-1 font-bold uppercase tracking-widest space-x-2">
254→              <MapPin size={12} />
255→              <span>{userLocation}</span>
256→            </div>
257→          )}
258→          {loadError && (
259→            <div className="mt-2 text-[10px] font-bold uppercase tracking-widest text-red-500">
260→              {loadError}
261→            </div>
262→          )}
263→          <div className="mt-4">
264→            <span className="px-4 py-1.5 bg-[#e7eef4] text-[#0f2b46] text-[10px] font-bold rounded-full uppercase tracking-widest border border-[#d5e1eb] shadow-sm">
265→              {t('Senior Contributor', 'Contributeur senior')}
266→            </span>
267→          </div>
268→        </div>
269→
270→        <div className="bg-[#0f2b46] rounded-2xl p-6 text-white shadow-xl flex items-center justify-between relative overflow-hidden">
271→          <div className="relative z-10 space-y-1">
272→            <span className="text-[10px] font-bold uppercase tracking-widest opacity-80">{t('XP Balance', 'Solde XP')}</span>
273→            <div className="flex items-baseline space-x-1">
274→              {isLoading ? (
275→                <div className="h-8 w-24 rounded-lg bg-white/20 animate-pulse"></div>
276→              ) : (
277→                <>
278→                  <h3 className="text-3xl font-extrabold tracking-tight">{profile?.XP?.toLocaleString?.() ?? '0'}</h3>
279→                  <span className="text-lg font-bold opacity-60">XP</span>
280→                </>
281→              )}
282→            </div>
283→          </div>
284→          <div className="relative z-10">
285→            <div className="w-12 h-12 bg-white/20 rounded-2xl flex items-center justify-center backdrop-blur-sm border border-white/30">
286→              <Award size={24} />
287→            </div>
288→          </div>
289→        </div>
290→
291→        {profile?.isAdmin && (
292→          <div className="bg-white p-5 rounded-2xl border border-gray-100 shadow-sm space-y-3">
293→            <div className="flex items-center justify-between">
294→              <div className="flex flex-col">
295→                <span className="text-[10px] font-bold uppercase tracking-widest text-gray-400">
296→                  {t('Admin Map Access', 'Acces carte admin')}
297→                </span>
298→                <span className="text-sm font-bold text-gray-900">
299→                  {t('Unlock worldwide map', 'Debloquer la carte mondiale')}
300→                </span>
301→              </div>
302→              <span className="inline-flex items-center rounded-full bg-[#eaf3ee] px-3 py-1 text-[10px] font-bold uppercase tracking-widest text-[#4c7c59]">
303→                {t('Enabled', 'Active')}
304→              </span>
305→            </div>
306→            <p className="text-xs text-gray-500">
307→              {isMapUnlocked
308→                ? t('Explorer map is unlocked worldwide.', 'La carte Explorer est debloquee dans le monde entier.')
309→                : t('Explorer map is locked to Bonamoussadi.', 'La carte Explorer est limitee a Bonamoussadi.')}
310→            </p>
311→          </div>
312→        )}
313→
314→        <div className="bg-white p-5 rounded-2xl border border-gray-100 shadow-sm space-y-3">
315→          <div className="flex items-center justify-between">
316→            <div className="flex flex-col">
317→              <span className="text-[10px] font-bold uppercase tracking-widest text-gray-400">
318→                {t('Collection Workflow', 'Workflow de collecte')}
319→              </span>
320→              <span className="text-sm font-bold text-gray-900">
321→                {t('My Weekly Assignments', 'Mes affectations hebdomadaires')}
322→              </span>
323→            </div>
324→            <span className="inline-flex items-center rounded-full bg-[#e7eef4] px-3 py-1 text-[10px] font-bold uppercase tracking-widest text-[#0f2b46]">
325→              {assignments.length}
326→            </span>
327→          </div>
328→
329→          {assignmentError && (
330→            <div className="rounded-xl border border-red-100 bg-red-50 p-3 text-[11px] text-red-600">
331→              {assignmentError}
332→            </div>
333→          )}
334→
335→          {isLoadingAssignments ? (
336→            <div className="text-xs text-gray-500">{t('Loading assignments...', 'Chargement des affectations...')}</div>
337→          ) : assignments.length === 0 ? (
338→            <div className="text-xs text-gray-500">
339→              {t('No active assignments yet.', 'Aucune affectation active pour le moment.')}
340→            </div>
341→          ) : (
342→            <div className="space-y-2">
343→              {assignments.map((assignment) => {
344→                const canStart = assignment.status === 'pending';
345→                const canComplete = assignment.status === 'in_progress';
346→                const isUpdating = isUpdatingAssignmentId === assignment.id;
347→                const statusLabel =
348→                  assignment.status === 'pending'
349→                    ? t('Pending', 'En attente')
350→                    : assignment.status === 'in_progress'
351→                      ? t('In progress', 'En cours')
352→                      : assignment.status === 'completed'
353→                        ? t('Completed', 'Termine')
354→                        : t('Expired', 'Expire');
355→                return (
356→                  <div key={assignment.id} className="rounded-xl border border-gray-100 p-3 bg-[#f9fafb] space-y-2">
357→                    <div className="flex items-center justify-between">
358→                      <div className="text-xs font-bold text-gray-900">{assignment.zoneLabel}</div>
359→                      <span className="text-[10px] font-bold uppercase tracking-widest text-gray-500">{statusLabel}</span>
360→                    </div>
361→                    <div className="text-[11px] text-gray-600">
362→                      {t('Due', 'Echeance')}: {assignment.dueDate}
363→                    </div>
364→                    <div className="text-[11px] text-gray-600">
365→                      {assignment.pointsSubmitted}/{assignment.pointsExpected} {t('points', 'points')} · {assignment.completionRate}%
366→                    </div>
367→                    <div className="text-[10px] text-gray-500">
368→                      {assignment.assignedVerticals
369→                        .map((vertical) => getCategoryLabelFromRegistry(vertical, language))
370→                        .join(', ')}
371→                    </div>
372→                    {(canStart || canComplete) && (
373→                      <button
374→                        type="button"
375→                        disabled={isUpdating}
376→                        onClick={() => handleAssignmentStatus(assignment.id, canStart ? 'in_progress' : 'completed')}
377→                        className={`h-9 rounded-xl px-3 text-[10px] font-bold uppercase tracking-widest ${
378→                          isUpdating ? 'bg-gray-100 text-gray-400' : 'bg-[#0f2b46] text-white'
379→                        }`}
380→                      >
381→                        {isUpdating
382→                          ? t('Updating...', 'Mise a jour...')
383→                          : canStart
384→                            ? t('Start Assignment', 'Demarrer affectation')
385→                            : t('Mark Completed', 'Marquer termine')}
386→                      </button>
387→                    )}
388→                  </div>
389→                );
390→              })}
391→            </div>
392→          )}
393→        </div>
394→
395→        <div className="grid grid-cols-2 gap-4">
396→          <button
397→            onClick={onRedeem}
398→            className="h-14 bg-white text-[#0f2b46] border border-[#d5e1eb] rounded-xl text-[10px] font-bold uppercase tracking-widest shadow-sm hover:bg-[#f2f4f7] transition-all flex items-center justify-center space-x-2"
399→          >
400→            <Gift size={16} />
401→            <span>{t('Redeem XP', 'Echanger XP')}</span>
402→          </button>
403→          <button className="h-14 bg-[#c86b4a] text-white rounded-xl text-[10px] font-bold uppercase tracking-widest shadow-lg hover:bg-[#b85f3f] transition-all flex items-center justify-center space-x-2">
404→            <Wallet size={16} />
405→            <span>{t('Convert to Rewards', 'Convertir en recompenses')}</span>
406→          </button>
407→        </div>
408→
409→        <div className="grid grid-cols-2 gap-4">
410→          <div className="bg-white p-5 rounded-2xl border border-gray-100 shadow-sm space-y-3">
411→            <div className="flex items-center space-x-2 text-[#4c7c59]">
412→              <BadgeCheck size={16} />
413→              <span className="text-[10px] font-bold uppercase tracking-widest">{t('Trust Score', 'Score de confiance')}</span>
414→            </div>
415→            <div className="flex flex-col">
416→              <span className="text-2xl font-bold text-gray-900">98%</span>
417→              <div className="mt-2 h-1 w-full bg-gray-50 rounded-full overflow-hidden">
418→                <div className="h-full bg-[#4c7c59] rounded-full transition-all duration-1000" style={{ width: '98%' }} />
419→              </div>
420→            </div>
421→          </div>
422→          <div className="bg-white p-5 rounded-2xl border border-gray-100 shadow-sm space-y-3">
423→            <div className="flex items-center space-x-2 text-[#0f2b46]">
424→              <Calendar size={16} />
425→              <span className="text-[10px] font-bold uppercase tracking-widest">{t('Badges', 'Badges')}</span>
426→            </div>
427→            <div className="flex flex-col">
428→              <span className="text-2xl font-bold text-gray-900">7</span>
429→              <p className="text-[10px] text-gray-400 font-bold uppercase tracking-wider">{t('Next: Urban Validator', 'Suivant : Validateur urbain')}</p>
430→            </div>
431→          </div>
432→        </div>
433→
434→        <div className="space-y-4">
435→          <div className="flex items-center justify-between px-1">
436→            <h4 className="text-[10px] font-bold text-gray-400 uppercase tracking-widest">{t('Contribution History', 'Historique des contributions')}</h4>
437→            <button className="text-[10px] font-bold text-[#0f2b46] uppercase">{t('View All', 'Voir tout')}</button>
438→          </div>
439→
440→          <div className="space-y-3">
441→            {history.length === 0 && (
442→              <div className="bg-white p-4 rounded-2xl border border-gray-100 shadow-sm text-xs text-gray-500">
443→                {t('No contributions yet. Add your first report to build your history.', 'Aucune contribution pour le moment. Ajoutez votre premier signalement pour construire votre historique.')}
444→              </div>
445→            )}
446→            {history.map((act) => (
447→              <div key={act.id} className="bg-white p-4 rounded-2xl border border-gray-100 shadow-sm flex items-center justify-between">
448→                <div className="flex items-center space-x-3">
449→                  <div className="w-10 h-10 rounded-xl bg-gray-50 flex items-center justify-center text-gray-400">
450→                    <Calendar size={18} />
451→                  </div>
452→                  <div className="flex flex-col">
453→                    <span className="text-xs font-bold text-gray-900">{act.type}</span>
454→                    <span className="text-[10px] text-gray-400 font-bold uppercase">{act.date}</span>
455→                    <span className="text-[10px] text-gray-400 font-medium">{act.location}</span>
456→                  </div>
457→                </div>
458→                <div className="text-right">
459→                  <p className="text-xs font-bold text-[#4c7c59]">+{act.xp} XP</p>
460→                </div>
461→              </div>
462→            ))}
463→          </div>
464→        </div>
465→
466→        <div className="space-y-4">
467→          <div className="flex items-center justify-between px-1">
468→            <h4 className="text-[10px] font-bold text-gray-400 uppercase tracking-widest">{t('Sync Errors', 'Erreurs de synchronisation')}</h4>
469→            {syncErrors.length > 0 && (
470→              <button
471→                type="button"
472→                onClick={handleClearSyncErrors}
473→                disabled={isClearingSyncErrors}
474→                className={`text-[10px] font-bold uppercase flex items-center space-x-1 ${isClearingSyncErrors ? 'text-gray-300' : 'text-[#c86b4a]'}`}
475→              >
476→                <Trash2 size={12} />
477→                <span>{isClearingSyncErrors ? t('Clearing...', 'Suppression...') : t('Clear', 'Effacer')}</span>
478→              </button>
479→            )}
480→          </div>
481→
482→          {syncErrorActionError && (
483→            <div className="bg-red-50 border border-red-100 rounded-2xl p-4 text-xs text-red-600">
484→              {syncErrorActionError}
485→            </div>
486→          )}
487→
488→          {isLoadingSyncErrors && (
489→            <div className="bg-white p-4 rounded-2xl border border-gray-100 shadow-sm text-xs text-gray-500">
490→              {t('Loading sync errors...', 'Chargement des erreurs de synchronisation...')}
491→            </div>
492→          )}
493→
494→          {!isLoadingSyncErrors && syncErrors.length === 0 && (
495→            <div className="bg-white p-4 rounded-2xl border border-gray-100 shadow-sm text-xs text-gray-500">
496→              {t('No sync errors on this device.', 'Aucune erreur de synchronisation sur cet appareil.')}
497→            </div>
498→          )}
499→
500→          {!isLoadingSyncErrors && syncErrors.length > 0 && (
501→            <div className="space-y-3">
502→              {syncErrors.map((record) => (
