 19→// Shared normalization helpers
 20→
 21→function trimString(input: unknown): string | undefined {
 22→  if (typeof input !== "string") return undefined;
 23→  const trimmed = input.trim();
 24→  return trimmed || undefined;
 25→}
 26→
 27→function normalizeBoolean(input: unknown): boolean | undefined {
 28→  if (typeof input === "boolean") return input;
 29→  if (typeof input === "number") {
 30→    if (input === 1) return true;
 31→    if (input === 0) return false;
 32→    return undefined;
 33→  }
 34→  if (typeof input !== "string") return undefined;
 35→  const normalized = input.trim().toLowerCase();
 36→  if (!normalized) return undefined;
 37→  if (["true", "yes", "y", "1", "open", "available", "oui"].includes(normalized)) return true;
 38→  if (["false", "no", "n", "0", "closed", "unavailable", "non"].includes(normalized)) return false;
 39→  return undefined;
 40→}
 41→
 42→function normalizeInteger(input: unknown): number | undefined {
 43→  if (typeof input === "number" && Number.isFinite(input)) return Math.round(input);
 44→  if (typeof input === "string" && input.trim()) {
 45→    const parsed = Number(input);
 46→    if (Number.isFinite(parsed)) return Math.round(parsed);
 47→  }
 48→  return undefined;
 49→}
 50→
 51→function normalizeStringArray(input: unknown): string[] | undefined {
 52→  if (Array.isArray(input)) {
 53→    const list = input
 54→      .map((value) => trimString(value))
 55→      .filter((value): value is string => Boolean(value));
 56→    return list.length ? Array.from(new Set(list)) : undefined;
 57→  }
 58→  const single = trimString(input);
 59→  return single ? [single] : undefined;
 60→}
 61→
 62→function normalizeProviders(input: unknown): string[] | undefined {
 63→  return normalizeStringArray(input);
 64→}
 65→
 66→// Identity normalizer for verticals with no special normalization logic
 67→function identityNormalize(d: SubmissionDetails): SubmissionDetails {
 68→  const details = { ...d };
 69→  const name = trimString(details.name) ?? trimString(details.siteName);
 70→  if (name) {
 71→    details.name = name;
 72→    details.siteName = name;
 73→  }
 74→
 75→  const openingHours = trimString((details as Record<string, unknown>).opening_hours) ?? trimString(details.openingHours);
 76→  if (openingHours) details.openingHours = openingHours;
 77→
 78→  const phone = trimString(details.phone);
 79→  if (phone) details.phone = phone;
 80→
 81→  const brand = trimString(details.brand);
 82→  if (brand) details.brand = brand;
 83→
 84→  return details;
 85→}
 86→
 87→// Per-vertical normalizers
 88→
 89→function normalizePharmacy(d: SubmissionDetails): SubmissionDetails {
 90→  const details = identityNormalize(d);
 91→  const raw = details as Record<string, unknown>;
 92→
 93→  if (typeof details.isOpenNow !== "boolean" && typeof details.availability === "string") {
 94→    const normalized = details.availability.toLowerCase();
 95→    details.isOpenNow = !normalized.includes("out") && !normalized.includes("closed");
 96→  }
 97→
 98→  const isOnDuty = normalizeBoolean(raw.isOnDuty ?? raw.isOnCall ?? raw.onDuty ?? raw.pharmacyDeGarde);
 99→  if (typeof isOnDuty === "boolean") details.isOnDuty = isOnDuty;
100→
101→  const isLicensed = normalizeBoolean(raw.isLicensed ?? raw.licensed);
102→  if (typeof isLicensed === "boolean") details.isLicensed = isLicensed;
103→
104→  const hasPrescriptionService = normalizeBoolean(raw.hasPrescriptionService ?? raw.prescriptionService);
105→  if (typeof hasPrescriptionService === "boolean") details.hasPrescriptionService = hasPrescriptionService;
106→
107→  const medicineCategories = normalizeStringArray(raw.medicineCategories ?? raw.medicine_types);
108→  if (medicineCategories) details.medicineCategories = medicineCategories;
109→
110→  if (typeof details.isOnDuty !== "boolean" && typeof details.availability === "string") {
111→    const normalized = details.availability.toLowerCase();
112→    if (normalized.includes("on-call") || normalized.includes("on call") || normalized.includes("garde")) {
113→      details.isOnDuty = true;
114→    }
115→  }
116→
117→  return details;
118→}
119→
120→function normalizeMobileMoney(d: SubmissionDetails): SubmissionDetails {
121→  const details = identityNormalize(d);
122→
123→  const providers = normalizeProviders(details.providers ?? details.provider);
124→  if (providers) details.providers = providers;
125→
126→  const cashThreshold =
127→    normalizeBoolean(details.hasMin50000XafAvailable) ??
128→    normalizeBoolean(details.hasCashAvailable) ??
129→    (typeof details.availability === "string" ? !details.availability.toLowerCase().includes("out") : undefined);
130→  if (typeof cashThreshold === "boolean") {
131→    details.hasMin50000XafAvailable = cashThreshold;
132→  }
133→  if ("hasCashAvailable" in details) {
134→    delete details.hasCashAvailable;
135→  }
136→
137→  const isActive = normalizeBoolean(details.isActive);
138→  if (typeof isActive === "boolean") details.isActive = isActive;
139→
140→  const hasFloat = normalizeBoolean(details.hasFloat);
141→  if (typeof hasFloat === "boolean") details.hasFloat = hasFloat;
142→
143→  const agentType = trimString(details.agentType);
144→  if (agentType) details.agentType = agentType;
145→
146→  if (details.merchantId && providers?.length && !details.merchantIdByProvider) {
147→    details.merchantIdByProvider = { [providers[0]]: details.merchantId };
148→  }
149→
150→  return details;
151→}
152→
153→function normalizeFuelStation(d: SubmissionDetails): SubmissionDetails {
154→  const details = identityNormalize(d);
155→
156→  const fuelType = trimString(details.fuelType);
157→  if (fuelType && !details.fuelTypes?.length) details.fuelTypes = [fuelType];
158→
159→  const parsedPrice =
160→    typeof details.fuelPrice === "number"
161→      ? details.fuelPrice
162→      : typeof details.price === "number"
163→        ? details.price
164→        : undefined;
165→
166→  if (typeof details.hasFuelAvailable !== "boolean" && typeof details.availability === "string") {
167→    details.hasFuelAvailable = !details.availability.toLowerCase().includes("out");
168→  }
169→
170→  if (parsedPrice !== undefined) {
171→    const priceKey = fuelType ?? "super";
172→    details.pricesByFuel = { ...(details.pricesByFuel ?? {}), [priceKey]: parsedPrice };
173→    details.fuelPrice = parsedPrice;
174→    details.price = parsedPrice;
175→  }
176→
177→  const queueLength = trimString(details.queueLength);
178→  if (queueLength) details.queueLength = queueLength;
179→
180→  return details;
181→}
182→
183→function normalizeTransportRoad(d: SubmissionDetails): SubmissionDetails {
184→  const details = identityNormalize(d);
185→  const roadName = trimString(details.roadName) ?? trimString(details.name);
186→  if (roadName) {
187→    details.roadName = roadName;
188→    details.name = roadName;
189→    details.siteName = roadName;
190→  }
191→
192→  const isBlocked = normalizeBoolean(details.isBlocked);
193→  if (typeof isBlocked === "boolean") details.isBlocked = isBlocked;
194→
195→  const passableBy = normalizeStringArray(details.passableBy);
196→  if (passableBy) details.passableBy = passableBy;
197→
198→  const condition = trimString(details.condition);
199→  if (condition) details.condition = condition;
200→
201→  const trafficLevel = trimString(details.trafficLevel);
202→  if (trafficLevel) details.trafficLevel = trafficLevel;
203→
204→  return details;
205→}
206→
207→function normalizeCensusProxy(d: SubmissionDetails): SubmissionDetails {
208→  const details = identityNormalize(d);
209→
210→  const storeyCount = normalizeInteger(details.storeyCount);
211→  if (storeyCount !== undefined) details.storeyCount = storeyCount;
212→
213→  const estimatedUnits = normalizeInteger(details.estimatedUnits);
214→  if (estimatedUnits !== undefined) details.estimatedUnits = estimatedUnits;
215→
216→  const hasCommercialGround = normalizeBoolean(details.hasCommercialGround);
217→  if (typeof hasCommercialGround === "boolean") details.hasCommercialGround = hasCommercialGround;
218→
219→  const hasElectricity = normalizeBoolean(details.hasElectricity);
220→  if (typeof hasElectricity === "boolean") details.hasElectricity = hasElectricity;
221→
222→  const hasWater = normalizeBoolean(details.hasWater);
223→  if (typeof hasWater === "boolean") details.hasWater = hasWater;
224→
225→  const commercialTypes = normalizeStringArray(details.commercialTypes);
226→  if (commercialTypes) details.commercialTypes = commercialTypes;
227→
228→  const nearbyInfrastructure = normalizeStringArray(details.nearbyInfrastructure);
229→  if (nearbyInfrastructure) details.nearbyInfrastructure = nearbyInfrastructure;
230→
231→  return details;
232→}
